"type": {
      "type": "string",
      "const": "error",
      "description": "Message type discriminator."
    },

"content_type": {
      "type": "string",
      "enum": [
        "plain",
        "markdown"
      ],
      "default": "plain",
      "description": "Content format, default = plain."
    },

"path": {
      "type": "string",
      "description": "RFC 9535 JSONPath to the component the message refers to (e.g., $.items[1])."
    },

"type": {
      "type": "string",
      "const": "warning",
      "description": "Message type discriminator."
    },

"content": {
      "type": "string",
      "description": "Human-readable warning message that MUST be displayed."
    },

"presentation": {
      "type": "string",
      "default": "notice",
      "description": "Rendering contract for this warning. 'notice' (default): platform MUST display, MAY dismiss. 'disclosure': platform MUST display in proximity to the path-referenced component, MUST NOT hide or auto-dismiss. See specification for full contract."
    },

"image_url": {
      "type": "string",
      "format": "uri",
      "description": "URL to a required visual element (e.g., warning symbol, energy class label)."
    },

"type": {
      "type": "string",
      "const": "info",
      "description": "Message type discriminator."
    },

"ucp": {
      "$ref": "../../ucp.json#/$defs/error",
      "description": "UCP protocol metadata. Status MUST be 'error' for error response."
    },

"messages": {
      "type": "array",
      "items": {
        "$ref": "message.json"
      },
      "minItems": 1,
      "description": "Array of messages describing why the operation failed."
    },

"oneOf": [
    {
      "$ref": "message_error.json"
    },
    {
      "$ref": "message_warning.json"
    },
    {
      "$ref": "message_info.json"
    }
  ]

"continue_url": {
      "type": "string",
      "format": "uri",
      "description": "URL for buyer handoff or session recovery."
    }
